import { useState, useRef } from 'react';
import { UploadCloud, FileAudio, X, Wand2, ArrowRight, Info } from 'lucide-react';
import { Btn, Bar, Spinner, Callout } from './ds';
import { transcribeFile } from '../api';

export default function UploadTab({ onAnalyze, loading }) {
  const [file,    setFile]  = useState(null);
  const [url,     setUrl]   = useState(null);
  const [text,    setText]  = useState('');
  const [phase,   setPhase] = useState('idle');
  const [pct,     setPct]   = useState(0);
  const [err,     setErr]   = useState('');
  const [drag,    setDrag]  = useState(false);

  const inputRef = useRef(null);

  const pick = f => {
    if (!f) return;
    const ok = f.type.startsWith('audio/') || /\.(mp3|wav|ogg|webm|m4a|flac|aac)$/i.test(f.name);
    if (!ok) { setErr('Unsupported format. Use MP3, WAV, OGG, WebM, M4A, FLAC or AAC.'); return; }
    if (f.size > 50e6) { setErr('Max file size is 50 MB.'); return; }
    setFile(f); setErr(''); setText(''); setPhase('idle'); setPct(0);
    if (url) URL.revokeObjectURL(url);
    setUrl(URL.createObjectURL(f));
  };

  const transcribe = async () => {
    if (!file) return;
    setPhase('working'); setPct(0); setErr('');
    let iv = setInterval(() => setPct(p => p < 85 ? p + Math.random() * 10 : p), 500);
    try {
      const t = await transcribeFile(file);
      clearInterval(iv); setPct(100);
      if (!t?.trim()) { setErr('No speech found in the file.'); setPhase('err'); return; }
      setText(t.trim()); setPhase('done');
    } catch (e) {
      clearInterval(iv);
      setErr(`Transcription failed: ${e.message}`); setPhase('err');
    }
  };

  const clear = () => {
    setFile(null); if (url) URL.revokeObjectURL(url); setUrl(null);
    setText(''); setPhase('idle'); setPct(0); setErr('');
  };

  const fmt = b => b < 1e6 ? `${(b / 1024).toFixed(0)} KB` : `${(b / 1e6).toFixed(1)} MB`;

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>

      {!file ? (
        /* ── Drop zone ── */
        <div
          onDragOver={e => { e.preventDefault(); setDrag(true); }}
          onDragLeave={() => setDrag(false)}
          onDrop={e => { e.preventDefault(); setDrag(false); pick(e.dataTransfer.files[0]); }}
          onClick={() => inputRef.current?.click()}
          style={{
            border: `1.5px dashed ${drag ? 'var(--accent)' : 'var(--rule-2)'}`,
            borderRadius: 'var(--r-lg)', padding: '44px 24px', textAlign: 'center',
            cursor: 'pointer',
            background: drag ? 'var(--accent-bg)' : 'var(--white)',
            transition: 'all 0.2s',
          }}
        >
          <input ref={inputRef} type='file' accept='audio/*' style={{ display: 'none' }}
            onChange={e => pick(e.target.files[0])} />

          <div style={{
            width: 44, height: 44, borderRadius: 11,
            background: drag ? 'var(--accent-2)' : 'var(--paper)',
            border: '1px solid var(--rule)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            margin: '0 auto 14px',
            transition: 'background 0.2s',
          }}>
            <UploadCloud size={20} color={drag ? 'var(--accent)' : 'var(--ink-3)'} />
          </div>

          <p style={{ fontSize: 14, fontWeight: 500, color: 'var(--ink)', marginBottom: 4 }}>
            Drop your audio file here
          </p>
          <p style={{ fontSize: 12.5, color: 'var(--ink-3)', marginBottom: 16 }}>or click to browse</p>

          <div style={{ display: 'flex', gap: 5, justifyContent: 'center', flexWrap: 'wrap' }}>
            {['MP3','WAV','OGG','M4A','FLAC','AAC'].map(f => (
              <span key={f} style={{
                padding: '2px 8px', background: 'var(--paper)',
                border: '1px solid var(--rule)', borderRadius: 4,
                fontSize: 10.5, fontWeight: 600, color: 'var(--ink-3)',
                fontFamily: 'var(--f-data)', letterSpacing: '0.04em',
              }}>{f}</span>
            ))}
          </div>
          <p style={{ fontSize: 11, color: 'var(--ink-5)', marginTop: 10 }}>Up to 50 MB</p>
        </div>

      ) : (
        /* ── File card ── */
        <div style={{ background: 'var(--white)', border: '1px solid var(--rule)', borderRadius: 'var(--r-lg)', overflow: 'hidden' }}>

          {/* File row */}
          <div style={{ padding: '13px 15px', borderBottom: '1px solid var(--rule)', display: 'flex', alignItems: 'center', gap: 11 }}>
            <div style={{
              width: 36, height: 36, borderRadius: 'var(--r)',
              background: 'var(--info-bg)', border: '1px solid var(--info-rule)',
              display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0,
            }}>
              <FileAudio size={16} color='var(--info)' />
            </div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <p style={{ fontSize: 13, fontWeight: 500, color: 'var(--ink)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', margin: 0 }}>{file.name}</p>
              <p style={{ fontSize: 11, color: 'var(--ink-4)', margin: 0, marginTop: 2 }}>{fmt(file.size)}</p>
            </div>
            <button onClick={clear} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--ink-4)', padding: 4, display: 'flex', borderRadius: 'var(--r)' }}>
              <X size={15} />
            </button>
          </div>

          {/* Audio preview */}
          {url && (
            <div style={{ padding: '12px 15px', borderBottom: '1px solid var(--rule)' }}>
              <audio controls src={url} style={{ width: '100%', height: 32 }} />
            </div>
          )}

          {/* Transcribe action */}
          <div style={{ padding: '12px 15px' }}>
            {phase === 'idle' && (
              <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                <Btn look='dark' Icon={Wand2} size='sm' onClick={transcribe} disabled={loading}>
                  Transcribe with Whisper
                </Btn>
                <span style={{ fontSize: 12, color: 'var(--ink-4)' }}>or paste below</span>
              </div>
            )}
            {phase === 'working' && (
              <div>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 7, alignItems: 'center' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 7, fontSize: 12.5, color: 'var(--info)' }}>
                    <Spinner size={13} color='var(--info)' />
                    Transcribing…
                  </div>
                  <span style={{ fontSize: 11.5, color: 'var(--ink-4)', fontFamily: 'var(--f-data)' }}>{Math.round(pct)}%</span>
                </div>
                <Bar value={pct} color='var(--info)' h={3} />
              </div>
            )}
          </div>
        </div>
      )}

      {/* Error */}
      {err && <Callout type='error' onClose={() => setErr('')}>{err}</Callout>}

      {/* Transcript box */}
      {file && (
        <div style={{
          background: 'var(--white)',
          border: `1px solid ${phase === 'done' ? 'var(--bull-rule)' : 'var(--rule)'}`,
          borderRadius: 'var(--r-md)', overflow: 'hidden',
          transition: 'border-color 0.3s',
        }}>
          <div style={{
            padding: '8px 13px',
            background: phase === 'done' ? 'var(--bull-bg)' : 'var(--paper)',
            borderBottom: '1px solid var(--rule)',
            display: 'flex', justifyContent: 'space-between', alignItems: 'center',
            transition: 'background 0.3s',
          }}>
            <span style={{ fontSize: 11, fontWeight: 600, color: phase === 'done' ? 'var(--bull)' : 'var(--ink-3)', letterSpacing: '0.05em', textTransform: 'uppercase' }}>
              {phase === 'done' ? 'Transcript — edit if needed' : 'Transcript — paste manually'}
            </span>
            {text && <span style={{ fontSize: 11, fontFamily: 'var(--f-data)', color: 'var(--ink-4)' }}>{text.length} chars</span>}
          </div>
          <textarea
            value={text}
            onChange={e => { setText(e.target.value); if (e.target.value.trim()) setPhase('done'); }}
            placeholder={"Transcript appears here, or paste manually...\n\nExample: \"Hi, I'm calling about Reliance Industries. I have ₹5 lakhs ready to invest...\""}
            style={{ width: '100%', minHeight: 110, padding: '13px', border: 'none', outline: 'none', fontSize: 13, lineHeight: 1.7, color: 'var(--ink)', fontFamily: 'var(--f-ui)', background: 'var(--white)', display: 'block' }}
          />
          {text.trim() && (
            <div style={{ padding: '10px 13px', background: 'var(--paper)', borderTop: '1px solid var(--rule)', display: 'flex', justifyContent: 'flex-end' }}>
              <Btn look='fill' Icon={ArrowRight} disabled={loading} onClick={() => onAnalyze(text)}>
                {loading ? 'Analyzing…' : 'Analyze'}
              </Btn>
            </div>
          )}
        </div>
      )}

      {!file && (
        <Callout type='info'>
          Upload a recorded client call. <strong>OpenAI Whisper</strong> on your backend handles transcription — 50+ languages, much more accurate than any browser API.
        </Callout>
      )}
    </div>
  );
}
